#include<bits/stdc++.h>
using namespace std;
string a_x_b(string A,int x,string ans=""){
	int a[100000]={0},c[100000]={0};
	int lena=A.size();
    for(int i=lena-1;i>=0;i--)a[lena-i]=A[i]-'0';
    int len=lena+log10(x)+1;
    for(int i=1;i<=lena;i++)c[i]=a[i]*x;
    for(int i=1;i<=len;i++)c[i+1]+=c[i]/10,c[i]%=10;
    while(c[len]==0)len--;
    for(int i=max(1,len);i>=1;i--)ans+=char(c[i]+'0');
    return ans;
}
string jc(int n,string ans="1"){
	for(int i=1;i<=n;i++)ans=a_x_b(ans,i);
	return ans;
}
int f(string s,char c,int ans=0){
	for(int i=0;i<s.size();i++)if(s[i]==c)ans++;
	return ans;
}
int main(void){
	int T,n;
	char c;
    cin>>T;
    while(T--){
    	cin>>n>>c;
    	cout<<f(jc(n),c)<<endl;
	}
	return false;
}
